        [HttpPost]
        public ActionResult ImportRegionProvinceShapeFile2(string boundary_type)
        {
            objRegionProvince.boundary_type = boundary_type;

            if (Request.Files.Count > 0)
            {
                HttpFileCollectionBase files = Request.Files;

                var userId = ((User)Session["userDetail"]).user_id;
                uploadDirectoryPath = Server.MapPath(ApplicationSettings.RegionProvinceShapeFilePath + "temp/");
                //Session["uploadedfilepath"] = uploadDirectoryPath.ToString();

                //create directory if not exist
                if (Directory.Exists(uploadDirectoryPath))
                    MiscHelper.CleanDirectorypath(uploadDirectoryPath, userId);
                else
                    Directory.CreateDirectory(uploadDirectoryPath);

                for (int i = 0; i < files.Count; i++)
                {
                    string filename = "";
                    HttpPostedFileBase file = files[i];
                    if (Request.Browser.Browser.ToUpper() == "IE" || Request.Browser.Browser.ToUpper() == "INTERNETEXPLORER")
                    {
                        string[] testfiles = file.FileName.Split(new char[] { '\\' });
                        filename = testfiles[testfiles.Length - 1];
                    }
                    else
                    {
                        filename = Path.GetFileName(Request.Files[i].FileName);
                    }

                    //PREPARE FILE NAME - USER SPECIFIC.
                    string filenamewithoutextension = Path.GetFileNameWithoutExtension(Request.Files[i].FileName);
                    string ext = System.IO.Path.GetExtension(filename);
                    filename = filenamewithoutextension + "_" + userId;
                    filename = filename + ext;
                    //SAVE FILE IN DIRECTORY
                    file.SaveAs(Path.Combine(uploadDirectoryPath, filename));
                }

                objRegionProvince.user_id = userId;
                objRegionProvince.uploadDirectoryPath = uploadDirectoryPath;
                objRegionPro = ReadRegionPorvinceFile(objRegionProvince);
                objImportRP.lstUpdateRegionProvince = objRegionPro.lstUpdateRegionProvince.OrderBy(x => x.region_name).ThenBy(x => x.region_abbreviation).ThenBy(x => x.province_name).ThenBy(x => x.province_abbreviation).ToList();
                objImportRP.pageMsg = objRegionPro.pageMsg;
                objImportRP.boundary_type = objRegionProvince.boundary_type;
            }
            else
            {
                objImportRP.pageMsg = new PageMessage() { status = ResponseStatus.FAILED.ToString(), message = "No file selected" };
            }
            Session["Imported_RegionProvince_FileData"] = objRegionPro;
            if (objImportRP.pageMsg.status != "OK")
            {
                JsonResult result = Json(new { result = objImportRP, Status = objRegionPro.pageMsg.status, Message = objRegionPro.pageMsg.message });
                result.MaxJsonLength = Int32.MaxValue;
                result.JsonRequestBehavior = JsonRequestBehavior.AllowGet;
                return result;
            }
            else
            {
                return PartialView("GetRegionProvinceUploadedList", objImportRP);
            }
        }
        [HttpPost]
        public ActionResult ImportRegionProvinceShapeFile(string boundary_type)
        {

            objRegionProvince.boundary_type = boundary_type;
            UploadSummary summary = new UploadSummary();

            if (Request.Files.Count > 0)
            {
                HttpFileCollectionBase files = Request.Files;
                summary = CheckFileExtension(files, summary);
                if (summary.status == StatusCodes.INVALID_FILE.ToString())
                {
                    return Json(summary);
                }
                var userId = ((User)Session["userDetail"]).user_id;
                uploadDirectoryPath = Server.MapPath(ApplicationSettings.RegionProvinceShapeFilePath + "temp/");

                Session["uploadedfilepath"] = uploadDirectoryPath.ToString();

                //create directory if not exist
                if (Directory.Exists(uploadDirectoryPath))
                  MiscHelper.CleanDirectorypath(uploadDirectoryPath, userId);
                else
                    Directory.CreateDirectory(uploadDirectoryPath);
                try
                {
                    for (int i = 0; i < files.Count; i++)
                    {
                        string filename = "";
                        HttpPostedFileBase file = files[i];
                        if (Request.Browser.Browser.ToUpper() == "IE" || Request.Browser.Browser.ToUpper() == "INTERNETEXPLORER")
                        {
                            string[] testfiles = file.FileName.Split(new char[] { '\\' });
                            filename = testfiles[testfiles.Length - 1];
                        }
                        else
                        {
                            filename = Path.GetFileName(Request.Files[i].FileName);
                        }

                        //PREPARE FILE NAME - USER SPECIFIC.
                        string filenamewithoutextension = Path.GetFileNameWithoutExtension(Request.Files[i].FileName);
                        string ext = System.IO.Path.GetExtension(filename);
                        filename = filenamewithoutextension + "_" + userId;
                        filename = filename + ext;
                        //SAVE FILE IN DIRECTORY
                        file.SaveAs(Path.Combine(uploadDirectoryPath, filename));
                    }
                    //summary.status = StatusCodes.OK.ToString();
                    objRegionProvince.user_id = userId;
                    objRegionProvince.uploadDirectoryPath = uploadDirectoryPath;
                    objRegionPro= ReadRegionPorvinceFile(objRegionProvince);
                    summary.status = objRegionPro.pageMsg.status;
                    summary.err_description= objRegionPro.pageMsg.message;
                    return Json(summary);
                }
                catch (Exception ex)
                {
                    summary.status = StatusCodes.FAILED.ToString();
                    summary.status_message = StatusCodes.FAILED.ToString();
                    summary.err_description = ex.Message;
                    ErrorLogHelper.WriteErrorLog("ImportRegionProvinceShapeFile", "RegionProvinceController", ex);
                    return Json(summary);
                }
            }
            else
            {
                return Json("No files selected.");
            }
        }

        public ActionResult getColumnMappping(string boundary_type, int templateId)
        {
           


            DataColumnCollection dc = (DataColumnCollection)Session["FileCoulms"];
            ColumnMappingTemplate objColumnMapping = new ColumnMappingTemplate();
            objColumnMapping.layer_id = 0;

            if (templateId > 0)
            {
                objColumnMapping.listMappedColumns = blDataUploader.getColumnsMapping(templateId);
                foreach (var column in objColumnMapping.listMappedColumns)
                {
                    objColumnMapping.listImportedColumns.Add(column.imported_column_name.ToString());
                }
            }
            else
            {
                objColumnMapping.listMappedColumns = blDataUploader.getRegionProvinceTemplateColumns(boundary_type);
                
                    foreach (var column in dc)
                    {
                        objColumnMapping.listImportedColumns.Add(column.ToString());
                    }
                
            }

            objColumnMapping.listTemplates = blDataUploader.getRegionProvinceMappingTemplates(0, Convert.ToInt32(Session["user_id"]), boundary_type);

            objColumnMapping.id = templateId;
            return PartialView("_RegionProvinceColumnMapping", objColumnMapping);
        }

        public ActionResult GetData(string boundary_type)
        {
            var list = Session["listMappedColumns"] as List<ColumnMapping>;
            List<NewColumns> listNewColumn = new List<NewColumns>();
            ErrorMessage status = new ErrorMessage();
            objRegionProvince.boundary_type = boundary_type;
            objRegionProvince.user_id = ((User)Session["userDetail"]).user_id;
            objRegionProvince.uploadDirectoryPath = Session["uploadedfilepath"].ToString();
            objRegionPro = ReadRegionPorvinceFile(objRegionProvince);
            List<Mapping> lstMapping = blDataUploader.GetRegionProvinceMapping(boundary_type);

            foreach (var item in list.ToList())
            {
                if (!string.IsNullOrEmpty(item.imported_column_name) && !string.IsNullOrEmpty(item.template_column_name) && item.template_column_name.ToLower() != item.imported_column_name.ToLower())
                {
                    bool isSource = lstMapping.Where(m => m.TemplateColName.ToUpper() == item.imported_column_name.ToUpper()).ToList().Count > 0;
                    listNewColumn.Add(
                        new NewColumns
                        {
                            sourceColumn = dt.Columns[item.imported_column_name].ColumnName,
                            destinationColumn = item.template_column_name,
                            isSourceTemplateColumn = isSource
                        });
                    DataColumnCollection dtColumns = dt.Columns;
                    if (!dtColumns.Contains(item.template_column_name))
                    {
                        dt.Columns.Add(item.template_column_name, dt.Columns[item.imported_column_name].DataType);
                    }
                }
            }
            CopyColumns(dt, listNewColumn);

            for (int i = 0; i < dt.Columns.Count; i++)
            {
                var dtcolName = dt.Columns[i].ColumnName.ToLower();
                foreach (var pair in lstMapping.ToList())
                {
                    if (dtcolName.Contains(pair.TemplateColName.ToLower()))
                    {
                        dt.Columns[i].ColumnName = pair.DbColName.ToString();
                    }
                }
            }

            objImportRP.lstUpdateRegionProvince = ConvertDataTable<UpdateGeomtaryProperties>(dt);

            objImportRP.pageMsg = objRegionPro.pageMsg;
            objImportRP.boundary_type = objRegionProvince.boundary_type;
            Session["Imported_RegionProvince_FileData"] = objRegionPro;
            if (objImportRP.pageMsg.status != "OK")
            {
                JsonResult result = Json(new { result = objImportRP, Status = objRegionPro.pageMsg.status, Message = objRegionPro.pageMsg.message });
                result.MaxJsonLength = Int32.MaxValue;
                result.JsonRequestBehavior = JsonRequestBehavior.AllowGet;
                return result;
            }
            else
            {
                return PartialView("GetRegionProvinceUploadedList", objImportRP);
            }
        }
        public UploadSummary CheckFileExtension(HttpFileCollectionBase files, UploadSummary summary)
        {
            summary.status = StatusCodes.OK.ToString();
            for (int i = 0; i < files.Count; i++)
            {
                HttpPostedFileBase file = files[i];
                string extension = Path.GetExtension(file.FileName).ToLower();
                if (!(extension == ".kml" || extension == ".xlsx" || extension == ".xls" || extension == ".kmz" || extension == ".shx" || extension == ".shp" || extension == ".prj" || extension == ".dbf" ||
                    extension == ".dxf" || extension == ".map" || extension == ".id" || extension == ".tab" || extension == ".dat"))
                {
                    summary.status = StatusCodes.INVALID_FILE.ToString();
                    summary.status_message = StatusCodes.INVALID_FILE.ToString();
                    summary.err_description = "Invalid File Extension. Please upload file having extension kml,kmz,xlsx,xls only";
                    //blDataUploader.UpdateStatus(summary);
                    return summary;
                }

            }
            return summary;
        }

        [HttpPost]
        public ActionResult SaveRegionProvinceShapFile(int[] lstUpdateRegionProvince)
        {
            PageMessage objMsg = new PageMessage();
            UpdateGeomtaryValue objRegionPro = new UpdateGeomtaryValue();
            Dictionary<string, string> lstLog = new Dictionary<string, string>();
            try
            {
                RegionProvince objRegionProvince = new RegionProvince();

                string uploadDirectoryPath = Server.MapPath(ApplicationSettings.RegionProvinceShapeFilePath + "temp/");
                string Savepath = Server.MapPath(ApplicationSettings.RegionProvinceShapeFilePath + "save/");

                List<string> strFileName = new List<string>();
                strFileName = Directory.GetFiles(uploadDirectoryPath).ToList();

                int user_id = ((User)Session["userDetail"]).user_id;
                string getshapefile_fullpath = "";
                MiscHelper mh = new MiscHelper();
                var SelectedRegProvList = ((UpdateGeomtaryValue)Session["Imported_RegionProvince_FileData"]);

                objRegionPro.lstUpdateRegionProvince = SelectedRegProvList.lstUpdateRegionProvince.Where(x => lstUpdateRegionProvince.Contains(x.id)).ToList();
                objRegionPro.pageMsg = SelectedRegProvList.pageMsg;
                string newFileName = string.Empty;
                for (int n = 0; n < strFileName.Count; n++)
                {

                    string filename = Path.GetFileName(strFileName[n].ToString());

                    if (Path.GetFileNameWithoutExtension(filename).Substring(filename.LastIndexOf('_') + 1) == Convert.ToString(user_id))
                    {
                        newFileName = string.Concat(Path.GetFileNameWithoutExtension(filename), "_", DateTimeHelper.Now.ToString("yyyyMMddHHmmss"), System.IO.Path.GetExtension(filename));
                        mh.CopyFile(uploadDirectoryPath, Savepath, filename, newFileName);
                        if (newFileName.Contains(".shp"))
                        {
                            getshapefile_fullpath = newFileName;
                        }
                    }
                }

                List<Status> message = new List<Status>();
                DataTable dt = new DataTable(objRegionPro.lstUpdateRegionProvince[0].boundarytype + "Log");
                dt.Columns.Add("Region");
                if (objRegionPro.lstUpdateRegionProvince[0].boundarytype.ToUpper() == "PROVINCE")
                {
                    dt.Columns.Add("Province");
                }
                dt.Columns.Add("Country");
                dt.Columns.Add("Status");
                dt.Columns.Add("Message");
                dt.Columns.Add("ResultStatus");
                DataRow dr;
                for (int n = 0; n < objRegionPro.lstUpdateRegionProvince.Count; n++)
                {
                    dr = dt.NewRow();
                    Status objstatus = new Status();

                    objRegionPro.lstUpdateRegionProvince[n].shapefilepath = getshapefile_fullpath;
                    objRegionPro.lstUpdateRegionProvince[n].created_by = user_id;
                    objRegionPro.lstUpdateRegionProvince[n].entryStatus = objRegionPro.lstUpdateRegionProvince[n].entryStatus.ToUpper() == "EXISTING" ? "EDIT" : objRegionPro.lstUpdateRegionProvince[n].entryStatus.ToUpper();
                    message = BLRegionProvince.Instance.SaveRegionProvinceGeomatery(objRegionPro.lstUpdateRegionProvince[n]);

                    if (message[0].status.ToLower().Contains("exception") || message[0].status.ToLower().Contains("failed"))
                    {
                        objMsg.status = ResponseStatus.FAILED.ToString();
                        objMsg.message = BLConvertMLanguage.MultilingualMessageConvert(message[0].message);//message[0].message;
                    }
                    else
                    {
                        objMsg.status = ResponseStatus.OK.ToString();
                        objMsg.message = message[0].status + " successfully.";
                    }

                    dr["Region"] = objRegionPro.lstUpdateRegionProvince[n].region_name;
                    if (objRegionPro.lstUpdateRegionProvince[0].boundarytype.ToUpper() == "PROVINCE")
                    {
                        dr["Province"] = objRegionPro.lstUpdateRegionProvince[n].province_name;
                    }
                    dr["Country"] = objRegionPro.lstUpdateRegionProvince[n].country_name;
                    dr["Status"] = message[0].status;
                    dr["Message"] = objMsg.message;
                    dr["ResultStatus"] = objMsg.status;
                    dt.Rows.Add(dr);
                }
                objRegionPro.pageMsg = objMsg;
                lstLog.Add("Total", dt.Rows.Count.ToString());
                lstLog.Add("Valid", dt.AsEnumerable().Where(x => x.Field<string>("ResultStatus").Contains("OK")).ToList().Count.ToString());
                lstLog.Add("Invalid", dt.AsEnumerable().Where(x => !x.Field<string>("ResultStatus").Contains("OK")).ToList().Count.ToString());
                dt.Columns.Remove("ResultStatus");
                if (dt.Rows.Count > 0)
                {
                    NPOIExcelHelper.DatatableToExcelFile("xlsx", dt, Savepath + newFileName.Split('.')[0] + "_Log.xls");
                }
                Session["RegionProvinceLog"] = dt;
            }

            catch (Exception ex)
            {
                objMsg.status = ResponseStatus.ERROR.ToString();
                objMsg.message = "Something went wrong!";
                objRegionPro.pageMsg = objMsg;
            }
            JsonResult result = Json(new { result = lstLog, Status = objMsg.status, Message = objMsg.message });
            result.MaxJsonLength = Int32.MaxValue;
            result.JsonRequestBehavior = JsonRequestBehavior.AllowGet;
            return result;
        }
        public void DownloadRegionProvinceLog()
        {
            DataTable dt = (DataTable)Session["RegionProvinceLog"];
            ExportData(dt, dt.TableName + "_" + DateTimeHelper.Now.ToString("ddMMyyyy") + " - " + DateTimeHelper.Now.ToString("HHmmss") + ".xls");
        }
        private void ExportData(DataTable dtReport, string fileName, bool isDataContainBarcode = false)
        {

            using (var exportData = new MemoryStream())
            {
                Response.Clear();
                if (dtReport != null && dtReport.Rows.Count > 0)
                {
                    if (string.IsNullOrEmpty(dtReport.TableName))
                        dtReport.TableName = fileName;
                    IWorkbook workbook = NPOIExcelHelper.DataTableToExcel("xlsx", dtReport, isDataContainBarcode);
                    workbook.Write(exportData);
                    Response.ContentType = "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet";
                    Response.AddHeader("Content-Disposition", string.Format("attachment;filename={0}", fileName + ".xlsx"));
                    Response.BinaryWrite(exportData.ToArray());
                    Response.End();
                }

                Response.End();
            }
        }
        private UpdateGeomtaryValue ReadRegionPorvinceFile(ImportRegionProvince objImportRP)
        {

            UpdateGeomtaryValue objupdategeomtary = new UpdateGeomtaryValue();
            try
            {

                PageMessage objMsg = new PageMessage();
                string[] fileEntries = Directory.GetFiles(objImportRP.uploadDirectoryPath, "*" + objImportRP.user_id + ".shp");
                BoundaryType boundaryType = (BoundaryType)Enum.Parse(typeof(BoundaryType), objImportRP.boundary_type);
                GeometryFactory factory = new GeometryFactory();
                string strMappingFilePath = Server.MapPath("~\\Content\\Templates\\RegionProvince\\" + objImportRP.boundary_type + "Template.xml");
                dt = NPOIExcelHelper.ShapeToDataTable(fileEntries[0]);

                if (!dt.Columns.Contains("id"))
                {
                    DataColumn colSRNo = new DataColumn("id", typeof(int));
                    dt.Columns.Add(colSRNo);
                }
                if (!dt.Columns.Contains("entryStatus"))
                {
                    DataColumn colSRNo = new DataColumn("entryStatus", typeof(string));
                    dt.Columns.Add(colSRNo);
                }
                
                Dictionary<string, string> dicColumnMapping = GetBulkUploadColumnMapping(strMappingFilePath);
                int shape_file_id = 1;
                using (ShapefileDataReader shapeFileDataReader = new ShapefileDataReader(fileEntries[0], factory))
                {
                    ShapefileHeader shpHeader = shapeFileDataReader.ShapeHeader;

                    if (shpHeader.ShapeType != ShapeGeometryType.Polygon && shpHeader.ShapeType != ShapeGeometryType.PolygonZM && shpHeader.ShapeType != ShapeGeometryType.PolygonZ)
                    {
                        objMsg.status = ResponseStatus.FAILED.ToString();
                        objMsg.message = "Shape file geometry  must be Polygon type! Uploaded geometry type is " + shpHeader.ShapeType;
                        objupdategeomtary.pageMsg = objMsg;
                        return objupdategeomtary;
                        //throw new Exception("Shape file geometry  must be Polygon type! Uploaded geometry type is " + shpHeader.ShapeType);
                    }
                    DbaseFileHeader header = shapeFileDataReader.DbaseHeader;
                    if (header.NumRecords == 0)
                    {
                        objMsg.status = ResponseStatus.FAILED.ToString();
                        objMsg.message = "Uploaded shape file is empty!";
                        objupdategeomtary.pageMsg = objMsg;
                        return objupdategeomtary;
                        //throw new Exception("Uploaded shape file is empty!");
                    }
                    else if (header.NumRecords > ApplicationSettings.RegProvMaxUploadRecords)
                    {
                        objMsg.status = ResponseStatus.FAILED.ToString();
                        objMsg.message = "Maximum " + ApplicationSettings.RegProvMaxUploadRecords + " record can be uploaded at a time!";
                        objupdategeomtary.pageMsg = objMsg;
                        return objupdategeomtary;
                    }
                    string[] shapeColumns = new string[header.NumFields];
                    for (int i = 0; i < header.NumFields; i++)
                    {
                        shapeColumns[i] = header.Fields[i].Name.ToUpper();
                    }
                    shapeFileDataReader.Reset();
                    CultureInfo cultureInfo = Thread.CurrentThread.CurrentCulture;
                    TextInfo textInfo = cultureInfo.TextInfo;
                    int ColumnValidation = 0; string ValidatedColumnName = string.Empty;
                    for (int p = 0; p < dicColumnMapping.Count; p++)
                    {
                        var status = shapeColumns.Any(a => a.ToLower() == dicColumnMapping.Values.ToList()[p].ToLower());
                        ColumnValidation = status == false ? ColumnValidation + 1 : ColumnValidation;
                        ValidatedColumnName = status == false ? (ValidatedColumnName == "" ? textInfo.ToTitleCase(dicColumnMapping.Values.ToList()[p]) : (ValidatedColumnName + ", " + textInfo.ToTitleCase(dicColumnMapping.Values.ToList()[p]))) : ValidatedColumnName;
                    }
                    if (ColumnValidation > 0)
                    {
                        objMsg.status = ResponseStatus.FAILED.ToString();
                        objMsg.message = "Below columns does not exists in " + boundaryType + " file.\n" + ValidatedColumnName;
                        objupdategeomtary.pageMsg = objMsg;
                        return objupdategeomtary;
                    }
                    //if (dicColumnMapping.Where(a => shapeColumns.Any(b => a.Value.ToLower() == b.ToLower())).ToList().Count() != dicColumnMapping.Count)
                    //{
                    //    objMsg.status = ResponseStatus.FAILED.ToString();
                    //    objMsg.message = "Required columns does not exists in " + boundaryType + " File!";
                    //    objupdategeomtary.pageMsg = objMsg;
                    //    return objupdategeomtary;
                    //}

                    var regionProvinceList = GetRegionProvinceDetailForExport("", boundaryType.ToString());// new BLRegionProvince().GetRegionProvinceDetails().ToList();
                    while (shapeFileDataReader.Read())
                    {
                        UpdateGeomtaryProperties objupdategeomtaryproperties = new UpdateGeomtaryProperties();

                        for (int i = 0; i < dicColumnMapping.Count; i++)
                        {

                            if (String.IsNullOrEmpty(shapeFileDataReader.GetValue(Array.IndexOf(shapeColumns, dicColumnMapping.OrderBy(key => key.Value).ElementAt(i).Value.ToString().ToUpper())).ToString().Trim()))
                            {
                                objMsg.status = ResponseStatus.FAILED.ToString();
                                objMsg.message = "Column name " + dicColumnMapping.OrderBy(key => key.Value).ElementAt(i).Value.ToString().ToUpper() + " values can not be blank.";
                                objupdategeomtary.pageMsg = objMsg;
                                return objupdategeomtary;
                            }
                        }
                        objupdategeomtaryproperties.region_name = Array.IndexOf(shapeColumns, dicColumnMapping.Values.ElementAt(0).ToUpper()) > -1 ? Convert.ToString(shapeFileDataReader.GetValue(Array.IndexOf(shapeColumns, dicColumnMapping.Values.ElementAt(0).ToUpper()))) : "";
                        objupdategeomtaryproperties.region_abbreviation = boundaryType.ToString().ToUpper() == "REGION" ? (Array.IndexOf(shapeColumns, dicColumnMapping.Values.ElementAt(1).ToUpper()) > -1 ? Convert.ToString(shapeFileDataReader.GetValue(Array.IndexOf(shapeColumns, dicColumnMapping.Values.ElementAt(1).ToUpper()))) : "") : "";
                        objupdategeomtaryproperties.province_name = boundaryType.ToString().ToUpper() == "REGION" ? "" : (Array.IndexOf(shapeColumns, dicColumnMapping.Values.ElementAt(1).ToUpper()) > -1 ? Convert.ToString(shapeFileDataReader.GetValue(Array.IndexOf(shapeColumns, dicColumnMapping.Values.ElementAt(1).ToUpper()))) : "");
                        objupdategeomtaryproperties.province_abbreviation = boundaryType.ToString().ToUpper() == "REGION" ? "" : (Array.IndexOf(shapeColumns, dicColumnMapping.Values.ElementAt(2).ToUpper()) > -1 ? Convert.ToString(shapeFileDataReader.GetValue(Array.IndexOf(shapeColumns, dicColumnMapping.Values.ElementAt(2).ToUpper()))) : "");
                        objupdategeomtaryproperties.country_name = Array.IndexOf(shapeColumns, dicColumnMapping.Values.ElementAt(boundaryType.ToString().ToUpper() == "REGION" ? 2 : 3).ToUpper()) > -1 ? Convert.ToString(shapeFileDataReader.GetValue(Array.IndexOf(shapeColumns, dicColumnMapping.Values.ElementAt(boundaryType.ToString().ToUpper() == "REGION" ? 2 : 3).ToUpper()))) : "";

                        objupdategeomtaryproperties.geomtext = ((Geometry)shapeFileDataReader.Geometry).AsText().ToString(CultureInfo.InvariantCulture);

                        //var feature = new Feature(shapeFileDataReader.Geometry, new AttributesTable());
                        // var gm = feature.Geometry ;
                        StringBuilder ff = new StringBuilder();
                        //objupdategeomtaryproperties.geomtext = Convert.ToBase64String(((Geometry)shapeFileDataReader.Geometry).AsBinary());

                        //IGeometry geometry = (Geometry)shapeFileDataReader.Geometry;
                        //ff.Append(geometry.AsText());
                        string existenceStatus = string.Empty;
                        if (boundaryType.ToString().ToUpper() == "REGION")
                        {
                            existenceStatus = regionProvinceList.AsEnumerable().Where(x => x.Field<string>("Region_Name") == objupdategeomtaryproperties.region_name && x.Field<string>("country_Name") == objupdategeomtaryproperties.country_name).Count() > 0 ? "Existing" : "New";
                            if (existenceStatus.ToUpper() != "NEW")
                            {
                                var details = regionProvinceList.AsEnumerable().Where(x => x.Field<string>("Region_Name") == objupdategeomtaryproperties.region_name && x.Field<string>("country_Name") == objupdategeomtaryproperties.country_name).CopyToDataTable();
                                if (details.Rows.Count > 0)
                                    objupdategeomtaryproperties.existing_id = Convert.ToInt32(details.Rows[0]["id"]);
                            }
                        }
                        else if (boundaryType.ToString().ToUpper() == "PROVINCE")
                        {
                            existenceStatus = regionProvinceList.AsEnumerable().Where(x => x.Field<string>("Region_Name") == objupdategeomtaryproperties.region_name && x.Field<string>("Province_Name") == objupdategeomtaryproperties.province_name && x.Field<string>("country_Name") == objupdategeomtaryproperties.country_name).Count() > 0 ? "Existing" : "New";
                            if (existenceStatus.ToUpper() != "NEW")
                            {
                                var details = regionProvinceList.AsEnumerable().Where(x => x.Field<string>("Region_Name") == objupdategeomtaryproperties.region_name && x.Field<string>("Province_Name") == objupdategeomtaryproperties.province_name && x.Field<string>("country_Name") == objupdategeomtaryproperties.country_name).CopyToDataTable();
                                if (details.Rows.Count > 0)
                                    objupdategeomtaryproperties.existing_id = Convert.ToInt32(details.Rows[0]["id"]);
                            }
                        }

                        objupdategeomtaryproperties.boundarytype = boundaryType.ToString();
                        objupdategeomtaryproperties.entryStatus = existenceStatus.ToString();
                        objupdategeomtaryproperties.id = shape_file_id; 
                        objMsg.status = ResponseStatus.OK.ToString();
                        objupdategeomtary.pageMsg = objMsg;
                        objupdategeomtary.lstUpdateRegionProvince.Add(objupdategeomtaryproperties);
                        dt.Rows[shape_file_id-1]["id"]= shape_file_id;
                        dt.Rows[shape_file_id-1]["entryStatus"] = existenceStatus.ToString();
                        shape_file_id++;
                    }
                }
                Session["FileCoulms"] = dt.Columns;
            }
            catch { throw; }
            return objupdategeomtary;
        }
        public Dictionary<string, string> GetBulkUploadColumnMapping(string filepath)
        {
            Dictionary<string, string> dicMapping = new Dictionary<string, string>();
            XDocument doc = XDocument.Load(filepath);
            return dicMapping = doc.Descendants("Mapping").OrderBy(s => (int)int.Parse(s.Attribute("id").Value))
                .Select(p => new
                {
                    DbColName = p.Element("DbColName").Value,
                    TemplateColName = p.Element("TemplateColName").Value
                })
                .ToDictionary(t => t.DbColName, t => t.TemplateColName);
        }
