        public void DownloadRegionProvince(string fileType, string regFilters, string provFilters)
        {
            if (!string.IsNullOrWhiteSpace(fileType))
            {
                Response.Cookies.Add(new HttpCookie("downloadStarted", "1"));
                var regProvfilters = string.Empty;
                if (fileType.ToUpper() == "EXCEL")
                {
                    if (String.IsNullOrEmpty(provFilters))
                        regProvfilters = "region_id in(" + regFilters + ")";
                    else
                        regProvfilters = "region_id in(" + regFilters + ") or province_id in (" + provFilters + ")";
                    DownloadRegionProvinceIntoExcel(regProvfilters);
                }
                else if (fileType.ToUpper() == "KML")
                {
                    if (String.IsNullOrEmpty(provFilters))
                        regProvfilters = "r.id in(" + regFilters + ")";
                    else
                        regProvfilters = "r.id in(" + regFilters + ") or p.id in (" + provFilters + ")";
                    DownloadRegionProvinceIntoKML(regProvfilters);
                }
                else if (fileType.ToUpper() == "SHAPE")
                {
                    if (String.IsNullOrEmpty(provFilters))
                        regProvfilters = "r.id in(" + regFilters + ")";
                    else
                        regProvfilters = "r.id in(" + regFilters + ") or p.id in (" + provFilters + ")";
                    DownloadRegionProvinceIntoShape(regProvfilters);
                }
                else if (fileType.ToUpper() == "TAB")
                {
                    if (String.IsNullOrEmpty(provFilters))
                        regProvfilters = "r.id in(" + regFilters + ")";
                    else
                        regProvfilters = "r.id in(" + regFilters + ") or p.id in (" + provFilters + ")";
                    DownloadRegionProvinceIntoTab(regProvfilters);
                }
            }

        }
        public DataTable GetRegionProvinceDetailForExport(string Filter, string ReportType)
        {
            ViewRegionProvinces objViewProvince = new ViewRegionProvinces();
            objViewProvince.lstViewRegionProvinceDetails = new BLRegionProvince().GetRegionProvinceList(objViewProvince.objGridAttributes, ReportType, Filter);

            DataTable datatable = new DataTable();
            datatable = MiscHelper.ListToDataTable(objViewProvince.lstViewRegionProvinceDetails);
            datatable.TableName = "RegionProvinceDetails";
            return datatable;
        }
        public void DownloadRegionProvinceIntoExcel(string filter)
        {
            try
            {
                DataTable dtReport = GetRegionProvinceDetailForExport(filter, "");
                if (dtReport != null && dtReport.Rows.Count > 0)
                {
                    dtReport.Columns.Add("Created On", typeof(string));
                    dtReport.Columns.Add("Modified On", typeof(string));

                    for (int i = 0; i < dtReport.Rows.Count; i++)
                    {
                        dtReport.Rows[i]["Created On"] = !String.IsNullOrEmpty(dtReport.Rows[i]["created_on"].ToString()) ? MiscHelper.FormatDateTime(dtReport.Rows[i]["created_on"].ToString()) : dtReport.Rows[i]["created_on"];
                        dtReport.Rows[i]["Modified On"] = !String.IsNullOrEmpty(dtReport.Rows[i]["modified_on"].ToString()) ? MiscHelper.FormatDateTime(dtReport.Rows[i]["modified_on"].ToString()) : dtReport.Rows[i]["modified_on"];
                    }
                    dtReport.Columns.Remove("lstViewRegionProvinceDetails"); dtReport.Columns.Remove("objGridAttributes");
                    dtReport.Columns.Remove("lstSearchBy"); dtReport.Columns.Remove("totalRecords");
                    dtReport.Columns.Remove("id"); dtReport.Columns.Remove("CREATED_BY"); dtReport.Columns.Remove("MODIFIED_BY");
                    dtReport.Columns.Remove("Created_on"); dtReport.Columns.Remove("Modified_on");
                    dtReport.Columns.Remove("geom"); dtReport.Columns.Remove("purpose");

