        public void DownloadRegionProvinceIntoKML(string filter)
        {
            StringBuilder sbPolygon = new StringBuilder();

            try
            {
                string polycolor = string.Empty;

                DataTable dt = GetRegionProvinceDetailForExport(filter, "KML");

                dt.Columns.Remove("lstViewRegionProvinceDetails"); dt.Columns.Remove("objGridAttributes");
                dt.Columns.Remove("lstSearchBy"); dt.Columns.Remove("totalRecords");
                dt.Columns.Remove("id"); dt.Columns.Remove("CREATED_BY"); dt.Columns.Remove("MODIFIED_BY");
                dt.Columns.Remove("CREATED_BY_TEXT"); dt.Columns.Remove("MODIFIED_BY_TEXT");
                dt.Columns.Remove("Created_on"); dt.Columns.Remove("Modified_on"); dt.Columns.Remove("SRNO");

                polycolor = "#ff0000ff";
                DataTable purpose = dt.DefaultView.ToTable(true, "Purpose");
                string ColumnName = string.Empty;
                string RowValue = string.Empty;
                DataTable PurposeWise = new DataTable();
                for (int i = 0; i < purpose.Rows.Count; i++)
                {
                    PurposeWise = new DataTable();
                    PurposeWise = dt.AsEnumerable().Where(x => x.Field<string>("purpose") == purpose.Rows[i][0].ToString()).OrderBy(x => x.Field<string>("Region_Name")).CopyToDataTable();
                    sbPolygon.Append("<Folder><name> " + purpose.Rows[i][0].ToString().ToUpper() + "</name>");
                    string placeMarkValue = string.Empty;
                    placeMarkValue = purpose.Rows[i][0].ToString().ToUpper() == "REGION" ? "REGION_NAME" : "PROVINCE_NAME";
                    for (int j = 0; j < PurposeWise.Rows.Count; j++)
                    {
                        StringBuilder description = new StringBuilder();
                        for (int k = 0; k < PurposeWise.Columns.Count; k++)
                        {
                            ColumnName = PurposeWise.Columns[k].ColumnName;
                            RowValue = PurposeWise.Rows[j][ColumnName].ToString();
                            if (purpose.Rows[i][0].ToString().ToUpper() == "REGION" && !ColumnName.ToUpper().Contains("PROVINCE"))
                            {
                                if (ColumnName.ToUpper() != "GEOM" && ColumnName.ToUpper() != "PURPOSE")
                                    description.Append("<SimpleData name='" + ColumnName + "'>" + (String.IsNullOrEmpty(RowValue) ? RowValue : RowValue.Replace("&", "&amp;")) + "</SimpleData>");
                            }
                            if (purpose.Rows[i][0].ToString().ToUpper() == "PROVINCE" && ColumnName.ToUpper() != "REGION_ABBREVIATION")
                            {
                                if (ColumnName.ToUpper() != "GEOM" && ColumnName.ToUpper() != "PURPOSE")
                                    description.Append("<SimpleData name='" + ColumnName + "'>" + (String.IsNullOrEmpty(RowValue) ? RowValue : RowValue.Replace("&", "&amp;")) + "</SimpleData>");
                            }
                        }
                        sbPolygon.Append("<Style id=\"transGreenPoly" + purpose.Rows[i][0].ToString().ToUpper()
                            + "\"><PolyStyle><color>"
                            + polycolor + "</color></PolyStyle></Style><Placemark><name>"
                            + PurposeWise.Rows[j][placeMarkValue].ToString().ToUpper() + "</name><ExtendedData><SchemaData schemaUrl='#UG'>"
                            + description +
                            "</SchemaData></ExtendedData><styleUrl>#transGreenPoly" +
                           purpose.Rows[i][0].ToString().ToUpper() + "</styleUrl>");

                        sbPolygon.Append("<Polygon><outerBoundaryIs><LinearRing><coordinates>");
                        if (!string.IsNullOrEmpty(PurposeWise.Rows[j]["geom"].ToString()))
                        {
                            string t = PurposeWise.Rows[j]["geom"].ToString().Substring(12, PurposeWise.Rows[j]["geom"].ToString().Length - 12);
                            string[] x = t.Split(',');
                            foreach (string y in x)
                            {
                                sbPolygon.Append(y.Split(' ')[0] + "," + y.Split(' ')[1] + "," + 0 + " ");
                            }
                        }
                        sbPolygon.Append("</coordinates></LinearRing></outerBoundaryIs></Polygon></Placemark>");
                    }
                    sbPolygon.Append("</Folder>");

                }
                string finalKMLString = "<?xml version=\"1.0\" encoding=\"iso-8859-1\"?>" +
                  "<kml xmlns=\"http://www.opengis.net/kml/2.2\" xmlns:gx=\"http://www.google.com/kml/ext/2.2\">" +
                              "<Document>  <!-- Begin Style Definitions -->" +
                            //"<Style id=\"cable\"><LineStyle><color>#ff0000ff</color><width>4</width></LineStyle></Style>" +
                            // "<Style id=\"logical\"><LineStyle><color>#ff0000ff</color><width>4</width></LineStyle></Style>" +
                            //"<Style id=\"transGreenPoly\"><LineStyle><color>#ff0000ff</color><width>2</width></LineStyle><PolyStyle><color>#ff0000ff</color></PolyStyle></Style>" +
                            //"<Style id=\"downArrowIcon\"><IconStyle><Icon><href>http://maps.google.com/mapfiles/kml/pal4/icon28.png</href></Icon></IconStyle></Style>" +
                            "<Style id=\"downArrowIcon\"><IconStyle><hotSpot x=\"20\" y=\"2\" xunits=\"pixels\" yunits=\"pixels\"/></IconStyle></Style>" +
                            sbPolygon.ToString() + "</Document></kml>";
                string FilePath = Server.MapPath(ApplicationSettings.RegionProvinceShapeFilePath + "temp/");
                string DesFilePath = Server.MapPath(ApplicationSettings.RegionProvinceShapeFilePath + "temp/") + "KML_" + Guid.NewGuid().ToString().Substring(0, 8);
                if (Directory.Exists(DesFilePath).Equals(false))
                    Directory.CreateDirectory(DesFilePath);
                string FileName = "RegionProvinceDetails_" + DateTimeHelper.Now.ToString("ddMMyyyy") + " - " + DateTimeHelper.Now.ToString("HHmmss") + ".kml";
                string fullPath = FilePath + FileName;

                System.IO.File.WriteAllText(fullPath, finalKMLString);
                MiscHelper mh = new MiscHelper();
                mh.CopyFile(FilePath, DesFilePath, FileName, FileName);

                string zipfilePath = DesFilePath + ".zip";

                using (var zip = new ZipFile())
                {
                    zip.AddDirectory(DesFilePath);
                    zip.Save(zipfilePath);
                }
                if (System.IO.File.Exists(zipfilePath))
                {
                    string fileName = Path.GetFileName(zipfilePath);
                    Directory.Delete(DesFilePath, true);
                }
                FileInfo file = new FileInfo(zipfilePath);
                Response.Clear();
                Response.AddHeader("Content-Disposition", "attachment; filename=RegionProvinceDetails_" + DateTimeHelper.Now.ToString("ddMMyyyy") + " - " + DateTimeHelper.Now.ToString("HHmmss") + ".zip");
                Response.AddHeader("Content-Length", file.Length.ToString());
                Response.ContentType = "application/zip";
                Response.WriteFile(file.FullName);
                Response.Flush();
                Response.End();
                System.IO.File.Delete(zipfilePath);
                System.IO.File.Delete(fullPath);
                //string attachment = "attachment; filename=RegionProvinceDetails_" + DateTimeHelper.Now.ToString("ddMMyyyy") + " - " + DateTimeHelper.Now.ToString("HHmmss") + ".kml";
                //Response.ClearContent();
                //Response.ContentType = "application/xml";
                //Response.AddHeader("content-disposition", attachment);
                //Response.Write(finalKMLString);
                //Response.End();
            }
            catch (Exception ex)
            {
                throw ex;
            }
        }

