                Directory.Delete(shapeFilePath, true);
            }
            FileInfo file = new FileInfo(ziptabPath);
            Response.Clear();
            Response.AddHeader("Content-Disposition", "attachment; filename=RegionProvince_" + DateTimeHelper.Now.ToString("ddMMyyyy") + " - " + DateTimeHelper.Now.ToString("HHmmss") + ".zip");
            Response.AddHeader("Content-Length", file.Length.ToString());
            Response.ContentType = "application/zip";
            Response.WriteFile(file.FullName);
            Response.Flush();
            Response.End();
            System.IO.File.Delete(ziptabPath);
        }

