        [HttpPost]
        public JsonResult GetRegionDetailbyProvinceGeom(string txtGeom)
        {
            UpdateGeomtaryValue objResp = new UpdateGeomtaryValue();

            var usrDetail = (User)Session["userDetail"];

            ////Restrict sales user to create entities...
            AuthorizeMessage obj = new AuthorizeMessage();
            obj = new AuthorizationHelper().IsAuthrozedForEntityCreation();

            if (!obj.status)
            {
                objResp.pageMsg.status = ResponseStatus.FAILED.ToString();
                objResp.pageMsg.message = obj.message;
                return Json(objResp, JsonRequestBehavior.AllowGet);
            }


            var objRegPro = BLRegionProvince.Instance.GetRegionDetailbyProvinceGeom(txtGeom);

            if (objRegPro != null)
            {
                objResp.lstUpdateRegionProvince.Add(new UpdateGeomtaryProperties());
                objResp.pageMsg.status = ResponseStatus.OK.ToString();
                objResp.lstUpdateRegionProvince[0].region_name = objRegPro[0].region_name;
                objResp.lstUpdateRegionProvince[0].country_name = objRegPro[0].country_name;
            }
            else
            {
                objResp.pageMsg.status = ResponseStatus.FAILED.ToString();
                objResp.pageMsg.message = "No Region exist at this location!";
            }
            return Json(objResp, JsonRequestBehavior.AllowGet);
        }
        [HttpPost]
        public JsonResult GetRegionProvinceGeomDetails(string filter, string boundaryType)
        {
            var regProvfilters = "";
            regProvfilters = boundaryType.ToUpper() == "REGION" ? "r.id in(" + filter + ") or p.id in (0)" : "r.id in(0) or p.id in (" + filter + ")";

            DataTable dt = GetRegionProvinceDetailForExport(regProvfilters, "KML");
            UpdateGeomtaryValue objRegionProvince = new UpdateGeomtaryValue();
            objRegionProvince.lstUpdateRegionProvince.Add(new UpdateGeomtaryProperties());
            objRegionProvince.lstUpdateRegionProvince[0].region_name = dt.Rows[0]["region_name"].ToString();
            objRegionProvince.lstUpdateRegionProvince[0].region_abbreviation = dt.Rows[0]["region_abbreviation"].ToString();
            objRegionProvince.lstUpdateRegionProvince[0].province_name = dt.Rows[0]["province_name"].ToString();
            objRegionProvince.lstUpdateRegionProvince[0].province_abbreviation = dt.Rows[0]["province_abbreviation"].ToString();
            objRegionProvince.lstUpdateRegionProvince[0].country_name = dt.Rows[0]["country_name"].ToString();
            objRegionProvince.lstUpdateRegionProvince[0].geomtext = dt.Rows[0]["geom"].ToString();
            objRegionProvince.lstUpdateRegionProvince[0].existing_id = Convert.ToInt32(filter);
            objRegionProvince.lstUpdateRegionProvince[0].IschkBoundary = dt.Rows.Count > 0 ? true : false;
            if (dt.Rows[0]["geometry_extent"].ToString() != null)
            {
                var extent = dt.Rows[0]["geometry_extent"].ToString().TrimStart("BOX(".ToCharArray()).TrimEnd(")".ToCharArray());
                string[] bounds = extent.Split(',');
                string[] southWest = bounds[0].Split(' ');
                string[] northEast = bounds[1].Split(' ');
                objRegionProvince.lstUpdateRegionProvince[0].southWest = new latlong { Lat = southWest[1], Long = southWest[0] };
                objRegionProvince.lstUpdateRegionProvince[0].northEast = new latlong { Lat = northEast[1], Long = northEast[0] };
            }
            return new JsonResult { Data = objRegionProvince.lstUpdateRegionProvince[0], JsonRequestBehavior = JsonRequestBehavior.AllowGet, MaxJsonLength = Int32.MaxValue };
        }
