        [HttpPost]
        public ActionResult ValidateRegionProvinceBoundary(int system_id, string entity_type, string geom, string action, string region_name, string region_abbreviation, string province_name, string province_abbreviation, string country)
        {
            JsonResponse<string> objVal = new JsonResponse<string>();
            var objValid = BLRegionProvince.Instance.ValidateRegionProvinceBoundary(system_id, entity_type, geom, action, region_name, region_abbreviation, province_name, province_abbreviation, country);

            if (objValid.status == false || objValid.result == "GEOMETRYCOLLECTION EMPTY")
            { 
                objVal.status = ResponseStatus.FAILED.ToString();                
                objVal.message = BLConvertMLanguage.MultilingualMessageConvert(objValid.message);//objValid.message;
                if (objValid.result == "GEOMETRYCOLLECTION EMPTY")
                {
                    objVal.message = "Failed";
                }

            }
            else
            {
                objVal.status = "SUCCESS";
                objVal.result = objValid.result;
            }
            return Json(objVal, JsonRequestBehavior.AllowGet);
        }

